        let c = Config::new(2, 8).unwrap();
        let mut h = HistogramArray::<28>::new(c).unwrap();
        h.record(3);
        h.record(3);
        let view = h.as_histogram();
        assert_eq!(view.total(), 2);
        assert_eq!(view.count_at(3), Some(2));
    }
}

