    pub const fn max_value_power(&self) -> u8 {
        self.max_value_power
    }

    /// Largest trackable value, `2^n - 1`.
    pub const fn max_value(&self) -> u64 {
        u64::MAX >> (64 - self.max_value_power as u32)
    }

